import java.util.*;

// Class representing tree nodes
class Node {
    int data;
    Node left, right;

    Node(int val) {
        data = val;
        left = right = null;
    }
}

// Solution class
class Solution {

    // Function to perform level order traversal
    public List<List<Integer>> levelOrder(Node root) {
        // Final result list
        List<List<Integer>> ans = new ArrayList<>();

        // Return empty list if tree is empty
        if (root == null) return ans;

        // Queue to store nodes during traversal
        Queue<Node> q = new LinkedList<>();

        // Add root node to the queue
        q.offer(root);

        // Loop while queue is not empty
        while (!q.isEmpty()) {
            // Number of nodes at current level
            int size = q.size();

            // List to store values of current level
            List<Integer> level = new ArrayList<>();

            // Traverse all nodes at this level
            for (int i = 0; i < size; i++) {
                // Remove node from queue
                Node node = q.poll();

                // Add its data to current level
                level.add(node.data);

                // Add left child if exists
                if (node.left != null) q.offer(node.left);

                // Add right child if exists
                if (node.right != null) q.offer(node.right);
            }

            // Add this level to result
            ans.add(level);
        }

        return ans;
    }

    // Function to get left view from level order
    public List<Integer> leftView(Node root) {
        List<List<Integer>> levels = levelOrder(root);
        List<Integer> left = new ArrayList<>();

        for (List<Integer> level : levels) {
            left.add(level.get(0));
        }

        return left;
    }

    // Function to get right view from level order
    public List<Integer> rightView(Node root) {
        List<List<Integer>> levels = levelOrder(root);
        List<Integer> right = new ArrayList<>();

        for (List<Integer> level : levels) {
            right.add(level.get(level.size() - 1));
        }

        return right;
    }
}

// Driver class with main function
public class Main {
    public static void main(String[] args) {
        // Build sample binary tree
        Node root = new Node(1);
        root.left = new Node(2);
        root.right = new Node(3);
        root.left.left = new Node(4);
        root.right.right = new Node(5);

        // Create solution object
        Solution sol = new Solution();

        // Get and print level order
        List<List<Integer>> levelOrder = sol.levelOrder(root);
        System.out.println("Level Order Traversal:");
        for (List<Integer> level : levelOrder) {
            for (int val : level) System.out.print(val + " ");
            System.out.println();
        }

        // Print left view
        System.out.println("Left View: " + sol.leftView(root));

        // Print right view
        System.out.println("Right View: " + sol.rightView(root));
    }
}

